mapper.select:
SELECT id, employee_id, base_salary, allowance, effective_date, created_at, updated_at
FROM employee_salary
WHERE employee_id = #{employeeId}

mapper.update:
UPDATE employee_salary
SET base_salary = #{baseSalary},
    allowance = #{allowance},
    effective_date = #{effectiveDate}
WHERE employee_id = #{employeeId}
